    #[test]
    fn test_async_context_execution_results() {
        // Test that execution results can be stored and retrieved
        let mut context = AsyncCommitmentutionContext::default();

        // Add some results
        let address = Address::ZERO;
        let result = Bytes::from(vec![0x42, 0x43, 0x44]);
        context.execution_results.insert(address, result.clone());

        // Verify results are stored
        assert!(!context.execution_results.is_empty());
        assert_eq!(context.execution_results.get(&address).unwrap(), &result);
    }

